SELECT [Sales Header].[Order Date], IIf([Order Type]=1,"Riass.",IIf([order type]=2,"Pronto",IIf([order type]=3,"Stock",IIf([order type]=4,"Sost.",IIf([order type]=0,"Progr",IIf([order type]=5,"PreSeason",IIf([order type]=17,"Commerciale","?"))))))) AS OrderType, [Sales Header].[Payment method Code], [Geographical Zone].Description AS GeoZone1, [Geographical Zone_1].Description AS GeoZone2, [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name, [Sales Header].[Sell-to Customer No_], Customer.Name, [AnalisiDateConsegnaVendite-Union].*, [Sales Header].[Ship-to City]
FROM ((((([AnalisiDateConsegnaVendite-Union] INNER JOIN [Sales Header] ON [AnalisiDateConsegnaVendite-Union].OrderNumber = [Sales Header].No_) INNER JOIN Customer ON [Sales Header].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN ([Sales Header Extension] LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [Sales Header Extension].[Geographical Zone 2] = [Geographical Zone_1].Code) ON [Sales Header].No_ = [Sales Header Extension].[Document No_]) LEFT JOIN [Ship-to Address] ON ([Sales Header].[Ship-to Code] = [Ship-to Address].Code) AND ([Sales Header].[Sell-to Customer No_] = [Ship-to Address].[Customer No_])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code;

